// --- BCS FAKTOR (synkronisert med registrering_v5 og forvalg_v4) ---
const BCS_FACTORS = { 1: 1.2, 2: 1.1, 3: 1.0, 4: 0.9, 5: 0.8 };
// ============================================================
// SPEC v2.4: Alle tabeller og hjelpefunksjoner fra PDF «Fôring av hest»
